package com.example.sharehandler

import android.content.Intent
import android.graphics.Bitmap
import android.net.Uri
import android.os.Bundle
import android.util.Log
import androidx.appcompat.app.AppCompatActivity
import java.io.File
import java.io.FileOutputStream

class ShareHandlerActivity : AppCompatActivity() {
    private val TAG = "ShareHandlerActivity"
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        val intent = intent
        val action = intent.action
        val type = intent.type
        
        if (Intent.ACTION_SEND == action && type != null) {
            handleSendIntent(intent)
        } else if (Intent.ACTION_SEND_MULTIPLE == action && type != null) {
            handleSendMultipleIntent(intent)
        }
        
        finish()
    }
    
    private fun handleSendIntent(intent: Intent) {
        when {
            "text/plain" == intent.type -> {
                val text = intent.getStringExtra(Intent.EXTRA_TEXT)
                if (text != null) {
                    processTextContent(text)
                }
            }
            type.startsWith("image/") -> {
                val uri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                if (uri != null) {
                    processImageContent(uri)
                }
            }
        }
    }
    
    private fun handleSendMultipleIntent(intent: Intent) {
        val uris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        if (uris != null) {
            for (uri in uris) {
                if (uri != null) {
                    processImageContent(uri)
                }
            }
        }
    }
    
    private fun processTextContent(text: String) {
        Log.d(TAG, "Received text content: $text")
        // Process URL extraction and handling
        val urlRegex = Regex("https?://[\\w\\-]+(\\.[\\w\\-]+)+([\\w\\-\\.,@?^=%&:/~\\+#]*[\\w\\-@?^=%&/~\\+#])?")
        val urls = urlRegex.findAll(text)
        urls.forEach { match ->
            Log.d(TAG, "Extracted URL: ${match.value}")
        }
    }
    
    private fun processImageContent(uri: Uri) {
        Log.d(TAG, "Received image content: $uri")
        // Process image handling
        try {
            val bitmap = contentResolver.openInputStream(uri)?.use { inputStream ->
                android.graphics.BitmapFactory.decodeStream(inputStream)
            }
            if (bitmap != null) {
                saveImage(bitmap)
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error processing image", e)
        }
    }
    
    private fun saveImage(bitmap: Bitmap) {
        val file = File(externalCacheDir, "shared_image_${System.currentTimeMillis()}.png")
        FileOutputStream(file).use { out ->
            bitmap.compress(Bitmap.CompressFormat.PNG, 90, out)
        }
        Log.d(TAG, "Image saved to: ${file.absolutePath}")
    }
}